VuexVuex集中式存储管理应用的所有组件的状态，并以相应的规则保证状态以可预测的方式发生变化。

安装Vuexvue add vuex

核心概念
state：状态、数据
mutations：更改状态的函数
action：异步操作
store：包含以上概念的容器

状态 - statestate保存应用状态
export default new Vuex.Store(&#123;  state: &#123;    counter: 0  &#125;&#125;)

&lt;h1&gt;  &#123;&#123;$store.state.counter&#125;&#125;&lt;&#x2F;h1&gt;



状态变更 - mutationsmutations用于修改状态
export default new Vuex.Store(&#123;  mutations:&#123;    add(state)&#123;      state.counter++    &#125;  &#125;&#125;)

&lt;h1 @click&#x3D;&quot;$store.commit(&#39;add&#39;)&quot;&gt;  &#123;&#123;$store.state.counter&#125;&#125;&lt;&#x2F;h1&gt;



派生状态 - getters从state派生出来新状态，类似计算属性
export default new Vuex.Store(&#123;  getters:&#123;    doubleCounter(state)&#123;      return state.counter * 2;    &#125;  &#125;&#125;)

&lt;h1&gt;  &#123;&#123;$store.getters.doubleCounter&#125;&#125;&lt;&#x2F;h1&gt;

动作 - actions添加业务逻辑，类似于controller
export default new Vuex.Store(&#123;  actions:&#123;    add(&#123;commit&#125;)&#123;      setTimeout(() =&gt; commit(&#x27;add&#x27;), 1000);    &#125;  &#125;&#125;)

&lt;h1 @tap&#x3D;&quot;$store.dispatch(&#39;add&#39;)&quot;&gt;  &#123;&#123;$store.state.counter&#125;&#125;&lt;&#x2F;h1&gt;



Vuex原理解析任务分析
实现插件
实现Store类
维持一个响应式状态state
实现commit()
实现dispatch()
实现getters


挂载$store



创建新的插件在Vue2.x项目中的src路径下，复制一份store文件，重命名为ou-store。
然后在ou-store路径下新建一个ou-vuex.js文件，并将index.js文件中的Vuex引入改为ou-vuex.js。
import Vuex from &#39;.&#x2F;ou-vuex&#39;

同时将main.js中的router引入也修改一下。
import router from &#39;.&#x2F;ou-vuex&#39;

创建vue的插件回头看一下store/index.js，首先是使用Vue.use()注册了Vuex，然后再实例化了Vuex.Store这个类，因此Vuex这个对象里含有一个install方法以及一个Store的类。
import Vue from &#x27;vue&#x27;import Vuex from &#x27;vuex&#x27;Vue.use(Vuex)export default new Vuex.Store(&#123;    ...&#125;)

因此我们来创建一个新的Vuex插件。
let Vue;    // 保存Vue的构造函数，插件中需要用到class Store &#123;&#125;function install(_Vue) &#123;    Vue = _Vue;&#125;export default &#123;Store, install&#125;;

挂载$storelet Vue;    // 保存Vue的构造函数，插件中需要用到class Store &#123;&#125;function install(_Vue) &#123;    Vue = _Vue;    Vue.mixin(&#123;        beforeCreate() &#123;            // 挂载$store            if(this.$options.store)&#123;                Vue.prototype.$store = this.$options.store;     // vm.$store            &#125;        &#125;    &#125;)&#125;export default &#123;Store, install&#125;;

实现响应式保存state数据因为state是一个对象，我们可以使用new Vue()将state转换为一个响应式数据进行保存起来。
其次，我们不能显式去保存这个state，暴露给外面，因此我们可以使用get和set去保存。
class Store &#123;    /*    * options:    *   state    *   mutations    *   actions    *   modules    *   getters    * */    constructor(options = &#123;&#125;) &#123;        // data响应式处理        this._vm = new Vue(&#123;               data: &#123;                $$state: options.state    // 通过this._vm._data.$$state 或 this._vm.$data.$$state 获取            &#125;        &#125;);    &#125;    // 获取state    get state() &#123;        return this._vm._data.$$state;    &#125;    // 不可设置state    set state(v) &#123;        console.error(&#x27;please use replaceState to reset state&#x27;);    &#125;&#125;

实现commit方法当我们使用commit方法时，都是$store.commit(type,payload)，第一个参数即mutations的type值，第二个是payload负载，而对应mutation方法的参数为state和payload，因此我们来实现：
class Store &#123;    constructor(options = &#123;&#125;) &#123;        this._vm = new Vue(&#123;            data: &#123;                $$state: options.state            &#125;        &#125;);        // 保存用户配置的mutations选项        this._mutations = options.mutations;    &#125;    get state() &#123;        return this._vm._data.$$state;    &#125;    set state(v) &#123;        console.error(&#x27;please use replaceState to reset state&#x27;);    &#125;    commit(type, payload) &#123;        // 获取type对应的mutation        const entry = this._mutations[type]        if(!entry) &#123;            console.error(`unknown mutation type : $&#123;type&#125;`);            return ;        &#125;        // 传递state和payload给mutation        entry(this.state, payload)    &#125;&#125;

实现dispatch方法dispatch方法跟commit方法大同小异，不同之处在于dispatch调用的是action异步函数，而action的参数为context和payload，payload我们可以通过dispatch的参数获取到，而context执行上下文其实就是实例中的this。
但action是用来处理异步函数的，因此我们需要对dispatch方法进行this绑定；同时，action方法中有可能会调用到commit方法，因此我们也需要对commit方法进行this绑定。
class Store &#123;    constructor(options = &#123;&#125;) &#123;        this._vm = new Vue(&#123;            data: &#123;                $$state: options.state             &#125;        &#125;);        // 保存用户配置的mutations选项和actions选项        this._mutations = options.mutations;        this._actions = options.actions;        // 将commit和dispatch绑定this，        this.commit = this.commit.bind(this);        this.dispatch = this.dispatch.bind(this);    &#125;    get state() &#123;        return this._vm._data.$$state;    &#125;    set state(v) &#123;        console.error(&#x27;please use replaceState to reset state&#x27;);    &#125;    commit(type, payload) &#123;        const entry = this._mutations[type]        if(!entry) &#123;            console.error(`unknown mutation type : $&#123;type&#125;`);            return ;        &#125;        entry(this.state, payload)    &#125;    dispatch(type, payload) &#123;        // 获取用户编写的type对应的action        const entry = this._actions[type];        if(!entry) &#123;            console.error(`unknown action type : $&#123;type&#125;`)        &#125;        // 异步结果处理常常需要返回Promise        return entry(this, payload)    &#125;&#125;

实现getters派生状态当我们定义getters状态时，实际上是定义了一个function。
getters: &#123;   doubleCounter(state) &#123;     return state.counter * 2;   &#125;&#125;,

而使用getters中某一个派生状态时，实际上是得到一个值，也就是这个function的返回值。
&lt;h4&gt;double count: &#123;&#123;$store.getters.doubleCounter&#125;&#125;&lt;&#x2F;h4&gt;

这其实就有点像对象中的get属性，因此我们可以使用Object.defineProperty()来实现getters。
class Store &#123;    constructor(options = &#123;&#125;) &#123;        this._vm = new Vue(&#123;            data: &#123;                $$state: options.state               &#125;        &#125;);        this._mutations = options.mutations;        this._actions = options.actions;        this.commit = this.commit.bind(this);        this.dispatch = this.dispatch.bind(this);        // 初始化getters，默认为一个空对象        this.getters = &#123;&#125;;        // 遍历options.getters        for (const key in options.getters) &#123;            const self = this;            Object.defineProperty(                this.getters,                key,   // key名                &#123;                    get() &#123;                      	// 调用对应的函数，第一个参数为state，将结果返回                        return options.getters[key](self._vm._data.$$state)                       &#125;                &#125;            )        &#125;    &#125;&#125;

https://github.com/OUDUIDUI/vue-source-code-study/tree/vue

Vue的设计思想Vue设计思想参考了MVVM模型，即将视图View和行为Model抽象化，即将视图UI和业务逻辑分开来，然后通过ViewModel层来实现双向数据绑定。
MVVM 与 MVC 最大的不同就是MVVM实现了 View 和 Model 的自动同步，也就是当Model 的属性改变时，我们不用再自己手动操作 Dom 元素，来改变 View 的显示，而是改变属性后该属性对应 View 层显示会自动改变。
MVVM框架的三个要素：数据响应式、模板引擎及其渲染。

数据响应式
监听数据变化并在视图中更新
在Vue2.x中，是根据Object.defineProperty()来实现数据响应式的


模板引擎
提供描述视图的模板语法
Vue的≈和指令v-bind、v-on、v-model等


渲染
将模板渲染成HTML进行显示



数据响应式原理在JavaScript的对象Object中有一个属性叫访问器属性，其中有[[Get]]和[[Set]]特性，它们分别是获取函数或设置函数，即在获取对象特定属性的时候回调用到。
而访问器属性是不能直接定义的，必须使用Object.defineProperty()进行定义。
const obj = &#123;  	_name: &#x27;Matt&#x27;&#125;;Object.defineProperty(obj, &#x27;name&#x27;, &#123;  	get() &#123;      	return this._name;    &#125;,  	set(newVal) &#123;      	console.log(&#x27;set name&#x27;)       	this._name = newVal;    &#125;&#125;)console.log(obj.name);   // &#x27;Matt&#x27;obj.name = &#x27;OUDUIDUI&#x27;;   // &#x27;set name&#x27;console.log(obj.name);   // &#x27;Henry&#x27;

而Vue2.x就是在set函数中进行监听，当数据发生变化了，就会进行响应操作。
因此，我们可以简单实现一个Vue中的defineReactive函数。
&lt;!DOCTYPE html&gt;&lt;html lang=&quot;en&quot;&gt;&lt;head&gt;    &lt;meta charset=&quot;UTF-8&quot;&gt;    &lt;title&gt;reactive app&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;div id=&quot;app&quot;&gt;&lt;/div&gt;&lt;script&gt;      /**     * defineReactive : 将对象中某一个属性设置为响应式数据     * @param obj&lt;Object&gt;: 对象     * @param key&lt;any&gt;: key名     * @param val&lt;any&gt;: 初始值     */    function defineReactive(obj, key, val) &#123;        Object.defineProperty(obj, key, &#123;            get() &#123;                console.log(`get $&#123;key&#125;`)                return val;   // 此时val存在obj的闭包里面            &#125;,            set(newVal) &#123;                console.log(`set $&#123;key&#125;`)                if (newVal !== val) &#123;                     val = newVal;                    update();    // 更新函数                &#125;            &#125;        &#125;)    &#125;    	/**     * update : 更新函数，重新渲染app DOM     */    function update() &#123;        const app = document.getElementById(&#x27;app&#x27;);        app.innerHTML = `obj.time = $&#123;obj.time&#125;`    &#125;    		const obj = &#123;&#125;; 		defineReactive(obj, &#x27;time&#x27;, new Date().toLacaleTimeString());  // 将obj进行响应式处理  	setInterval(() =&gt; obj.time = new Date().toLacaleTimeString(), 1000);   // 定时更新obj.time的值&lt;/script&gt;

在代码中，我们在set中，调用了update更新函数，因此我们定时器每更新obj.time一次，update函数就会被调用一次，因此页面数据也会更新一次。这时候，我们就简单的实现了数据响应式。
但defineReactive函数有个问题，就是一次只能对一个属性值进行响应式处理，而且如果这个属性是个对象的话，我们更改对象里面的值的时候，是实现不了响应式的。
const obj = &#123;&#125;;defineReactive(obj, &#x27;info&#x27;, &#123;name: &#x27;OUDUIDUI&#x27;, age: 18&#125;);  // 将obj进行响应式处理setTimeout(() =&gt; obj.info.age++, 1000);  // 这时候不会触发set函数


因此，我们需要一个新的方法去实现对整个对象进行响应式处理，在Vue中这个方法叫observe。
在这个函数中，我们先需要对传入的obj进行类型判断，然后对对象进行遍历，对每一个属性进行响应式处理。这个地方需要对数组做处理，这个放到后面再说。
/** * observe: 将整个对象设置为响应式数据 * @param obj&lt;Object&gt;: 对象 */function observe(obj) &#123;    // 如果obj不是对象的话，跳出函数    if (typeof obj !== &quot;object&quot; || obj === null) &#123;        return;    &#125;    // 判断传入obj的类型    if(Array.isArray(obj))&#123;        // TODO    &#125;else &#123;        // 遍历obj所有所有key，做响应式处理        Object.keys(obj).forEach(key =&gt; &#123;            defineReactive(obj, key, obj[key]);        &#125;)    &#125;&#125;

同时，我们需要实现对这个对象一个递归处理，因此我们需要修改一下defineReactive函数。我们只需要在最开始的地方，调用一次observe函数，如果传入的val是对象，就会进行递归响应式处理，如果不是就返回。
function defineReactive(obj, key, val) &#123;    observe(val);  // 递归处理：如果val是对象，继续做响应式处理    Object.defineProperty(obj, key, &#123;        ...    &#125;)&#125;

我们来测试一下：
const obj = &#123;    time: new Date().toLocaleTimeString(),    info: &#123;        name: &#x27;OUDUIDUI&#x27;,        age: 18    &#125;&#125;;observe(obj);setInterval(() =&gt; &#123;    obj.time = new Date().toLocaleTimeString();&#125;, 1000)setTimeout(() =&gt; &#123;    obj.info.age++;&#125;, 2000)


这里还有一个小问题，就是如果obj原本有一个属性是常规类型，即字符串、数值等等，然后再将其改为引用类型时，如对象、数值等，该引用类型内部的属性，是没有响应式的。比如下来这种情况：
const obj = &#123;    text: &#x27;Hello World&#x27;,&#125;;observe(obj);  // 响应式处理obj.text = &#123; en: &#x27;Hello World&#x27; &#125;;    // 将obj.text由字符串改成一个对象setTimeout(() =&gt; &#123;    obj.text.en = &#x27;Hi World&#x27;;   // 此时修改text对象属性页面是不会更新的，因为obj.text.en不是响应式数据&#125;, 2000)

对于这种情况，我们只需要在defineReactive函数中，set的时候调用一下observe函数，将newVal传入，如果是对象就进行响应式处理，否则就直接返回。
function defineReactive(obj, key, val) &#123;    observe(val);     Object.defineProperty(obj, key, &#123;        get() &#123;            console.log(`get $&#123;key&#125;`)            return val;        &#125;,        set(newVal) &#123;            console.log(`set $&#123;key&#125;`)            if (newVal !== val) &#123;                observe(newVal);  // 如果newVal是对象，再次做响应式处理                val = newVal;                update();            &#125;        &#125;    &#125;)&#125;

我们测试一下。
function update() &#123;    const app = document.getElementById(&#x27;app&#x27;);    app.innerHTML = `obj.text = $&#123;JSON.stringify(obj.text)&#125;`&#125;const obj = &#123;    text: &#x27;Hello World&#x27;&#125;;// 响应式处理observe(obj);setTimeout(() =&gt; &#123;    obj.text = &#123;     // 将obj.text由字符串改成一个对象        en: &#x27;Hello World&#x27;    &#125;&#125;, 2000)setTimeout(() =&gt; &#123;    obj.text.en = &#x27;Hi World&#x27;;&#125;, 4000)


最后我们来完成前面楼下的一个问题，就是数组的响应式处理。
之所以数组需要特殊处理，因为数组有七个自带方法可以去处理数组的内容，分别是push、pop、shift、unshift、reverse、sort、splice，它们都是可以修改数组本身的。
所以，我们需要对七个方法进行监听。我们可以先克隆一个新的数组原型，然后在新的原型中，新建这七个方法，先执行对应的方法操作后，进行数据响应式更新处理。
// 数组响应式const originalProto = Array.prototype;const arrayProto = Object.create(originalProto);  // 以Array.prototype为原型创新一个新对象[&#x27;push&#x27;, &#x27;pop&#x27;, &#x27;shift&#x27;, &#x27;unshift&#x27;,&#x27;reverse&#x27;, &#x27;sort&#x27;, &#x27;splice&#x27;].forEach(method =&gt; &#123;    arrayProto[method] = function () &#123;        // 原始操作        originalProto[method].apply(this, arguments);        // 覆盖操作：通知更新        update();    &#125;&#125;)

然后继续完成observe函数操作。
如果类型是数组的话，将其的原型进行覆盖，然后再数组每一个元素进行响应式处理。
function observe(obj) &#123;    if (typeof obj !== &quot;object&quot; || obj === null) &#123;        return;    &#125;    // 判断传入obj的类型    if (Array.isArray(obj)) &#123;        // 覆盖原型        obj.__proto__ = arrayProto;        // 对数组内部原型执行响应式        for (let i = 0; i &lt; obj.length; i++) &#123;            observe(obj[i]);         &#125;    &#125; else &#123;        Object.keys(obj).forEach(key =&gt; &#123;            defineReactive(obj, key, obj[key]);        &#125;)    &#125;&#125;

测试一下：
function update() &#123;    const app = document.getElementById(&#x27;app&#x27;);    app.innerHTML = `obj.nums = $&#123;JSON.stringify(obj.nums)&#125;`&#125;const obj = &#123;    nums: [4, 2, 3]&#125;;// 响应式处理observe(obj);setTimeout(() =&gt; &#123;    obj.nums.push(1);&#125;, 2000)setTimeout(() =&gt; &#123;    obj.nums.sort((a,b) =&gt; a - b);&#125;, 4000)


简单手写Vue原理分析当我们使用vue的时候，首先都会创建一个Vue实例，然后在里面初始化element、data、methods等等。
const app = new Vue(&#123;    el: &#x27;#app&#x27;,    data: &#123;      	count: 1    &#125;,    methods:&#123;&#125;&#125;);

然后我们可以在data里面设置一些变量，而这些变量会被处理为响应式数据，然后我们就可以使用模板语句去渲染data数据。
&lt;div id=&quot;app&quot;&gt;    &lt;p&gt;&#123;&#123;counter&#125;&#125;&lt;/p&gt;&lt;/div&gt;

所以我们需要实现的功能就是对data进行响应式处理、编译和渲染模板、以及数据变化时更新模板。
因此我们创建Vue实例需要实现以下内容：

对data执行响应式处理，这个过程发生在Observer中；
对模板执行编译，找到其中动态绑定的数据，从data中获取并初始化视图，这个过程发生在Compile中；
每创建一个响应式数据，同时定义一个更新函数和Watcher，将来对应数据变化时Watcher会调用更新函数；
由于data的某个key在一个视图中可能出现多次，所以每个key都需要一个依赖Dependence来管理多个Watcher；将来data中数据一旦发生变化，会首先找到对应的Dependence，然后Dependence通知对应所有的Watcher执行更新函数。


实现数据响应式首先我们新建一个vue.js，创建一个Vue的类，在constructor对参数数据进行保存。
/** * Vue: *   1. 对data选项做响应式处理 *   2. 编译模板 * @param options&lt;Object&gt;: 包含el、data、methods等等 */class Vue &#123;    constructor(options) &#123;        this.$options = options;        this.$data = options.data;    // data选项            	// 对data进行响应式处理        observe(this.$data);    &#125;&#125;

observe()方法跟前面所说的类似，只不过我们把大部分内容放入Observer类中，因为我们需要对每一个响应式数据进行监听并通知Dep。
/** * observe: 将整个对象设置为响应式数据 * @param obj&lt;Object&gt;: 对象 */function observe(obj) &#123;    // 如果obj不是对象的话，跳出函数    if (typeof obj !== &quot;object&quot; || obj === null) &#123;        return;    &#125;    // 响应式处理    new Observer(obj);&#125;

Observer中constructor构造函数的内容，基本就是之前observe方法中的内容，以及类中的defineReactive方法也跟前面讲的一致，这里就不说了。
唯一不同的是，这里不再是调用update函数，而在后面我们需要创建一个依赖Dependence实例并调用，现在我们先留空着。
/** * Observer: *   1. 根据传入value的类型做响应的响应式处理 * @param value&lt;Object || Array&gt; */class Observer &#123;    constructor(value) &#123;        this.value = value;        // 数据类型判断        if(Array.isArray(value))&#123;            // 覆盖原型            value.__proto__ = this.getArrayProto();            // 对数组内部原型执行响应式            for (let i = 0; i &lt; value.length; i++) &#123;                observe(value[i]);            &#125;        &#125;else &#123;            // 遍历obj所有所有key，做响应式处理            Object.keys(value).forEach(key =&gt; &#123;                this.defineReactive(value, key, value[key]);            &#125;)        &#125;    &#125;    getArrayProto() &#123;      	const self = this;      	        const originalProto = Array.prototype;        const arrayProto = Object.create(originalProto);         [&#x27;push&#x27;, &#x27;pop&#x27;, &#x27;shift&#x27;, &#x27;unshift&#x27;,&#x27;reverse&#x27;, &#x27;sort&#x27;, &#x27;splice&#x27;].forEach(method =&gt; &#123;            arrayProto[method] = function () &#123;                originalProto[method].apply(self, arguments);                              // TODO 通知变化            &#125;        &#125;)        return arrayProto;    &#125;    /**     * defineReactive : 将对象中某一个属性设置为响应式数据     * @param obj&lt;Object&gt;: 对象     * @param key&lt;any&gt;: key名     * @param val&lt;any&gt;: 初始值     */    defineReactive(obj, key, val) &#123;        observe(val);         Object.defineProperty(obj, key, &#123;            get() &#123;                Dependence.target &amp;&amp; dep.addDep(Dependence.target);                return val;            &#125;,            set(newVal) &#123;                if (newVal !== val) &#123;                    observe(newVal);                    val = newVal;										                  	// TODO 通知变化                &#125;            &#125;        &#125;)    &#125;&#125;

现在我们基本实现了对data数据进行响应式处理。
但现在我们在JavaScript中创建了Vue实例后，我们无法直接在实例中获取到data数据，而是需要通过实例中的$data中获取到data的内容。
const app = new Vue(&#123;    el: &#x27;#app&#x27;,    data: &#123;        desc: &#x27;HelloWorld&#x27;,    &#125;&#125;);console.log(app.desc);   	// undefinedconsole.log(app.$data.desc);   // &#x27;HelloWorld&#x27;

因为我们得对data中的数据实现一下代理，代理的实现也是通过对象的访问器属性实现，这里也不多说。
class Vue &#123;    constructor(options) &#123;        this.$options = options;        this.$data = options.data;        observe(this.$data);        // 代理        proxy(this);    &#125;&#125;/** * proxy: 数据代理 * @param vm&lt;Object&gt; */function proxy(vm) &#123;    Object.keys(vm.$data).forEach(key =&gt; &#123;        Object.defineProperty(vm, key, &#123;            get() &#123;                return vm.$data[key]            &#125;,            set(v) &#123;                vm.$data[key] = v;            &#125;        &#125;)    &#125;)&#125;

这时候我们就可以用app.desc访问到data.desc属性了。
模板编译和渲染在我们实现数据响应式后，我们就可以对模板进行编译和渲染，这时候就需要来实现Compile类。
class Vue &#123;    constructor(options) &#123;        this.$options = options;        this.$data = options.data;    // data选项        observe(this.$data);        proxy(this);        // 模板编译和渲染        new Compile(options.el, this);    &#125;&#125;

Compile类的构造函数接收两个参数，一个是element，一个是Vue实例中的this，这个实际上就是View Model的数据，也是我们在Vue中常见的vm。
在构造函数中，先对传入数据进行保存，然后获取节点，如果节点存在的话，就开始进行编译处理。
/** * Compile: *   1. 解析模板 *      a. 处理插值 *      b. 处理指令和事件 *      c. 以上两者初始化和更新 * @param el * @param vm */class Compile &#123;    constructor(el, vm) &#123;        this.$vm = vm;        this.$el = document.querySelector(el);        if(this.$el)&#123;          	// 编译节点            this.compile(this.$el);        &#125;    &#125;  	/**     * compile: 递归节点，对节点进行编译     * @param el     */    compile(el)&#123; &#125;&#125;

首先，我们需要对节点进行递归遍历，然后通过nodeType识别出当前节点的信息，如果是元素节点的话，我们需要对其进行指令和事件处理，如果是文本节点的话，同时含有插槽的话，我们需要对齐进行文本替换处理。
class Compile &#123;    constructor(el, vm) &#123; ... &#125;    /**     * compile: 递归节点，对节点进行编译     * @param el     */    compile(el)&#123;        // 遍历el子节点，判断他们类型做相应的处理        const childNodes = el.childNodes;        childNodes.forEach(node =&gt; &#123;            if(node.nodeType === 1)&#123;                // 元素                console.log(&#x27;元素&#x27;, node.nodeName);              	// TODO 指令和事件处理            &#125;else if(this.isInter(node))&#123;                // 文本                console.log(&#x27;文本&#x27;, node.textContent);              	// TODO 文本替换处理            &#125;                      // 递归            if(node.childNodes)&#123;                this.compile(node);            &#125;        &#125;)    &#125;    // 判断是否为插值表达式    isInter(node) &#123;        return node.nodeType === 3 &amp;&amp; /\&#123;\&#123;(.*)\&#125;\&#125;/.test(node.textContent);    &#125;&#125;

首先我们来实现一下文本编译。
因为我们前面判断的时候，使用过正则去判断node.textContent，因此如果符合标准的话，我们就可以通过RegExp.$1获取到属性名，因此我们就可以那属性名去data中进行匹配。
class Compile &#123;    constructor(el, vm) &#123; ... &#125;    compile(el)&#123;        const childNodes = el.childNodes;        childNodes.forEach(node =&gt; &#123;            if(node.nodeType === 1)&#123;              	// TODO 指令和事件处理            &#125;else if(this.isInter(node))&#123;              	// 文本初始化                this.compileText(node);            &#125;                      if(node.childNodes)&#123;                this.compile(node);            &#125;        &#125;)    &#125;    // 编译文本    compileText(node) &#123;        node.textContent = this.$vm[RegExp.$1];    &#125;&#125;

这时候，我们可以测试一下。
&lt;!doctype html&gt;&lt;html lang=&quot;en&quot;&gt;&lt;head&gt;    &lt;meta charset=&quot;UTF-8&quot;&gt;    &lt;meta name=&quot;viewport&quot;          content=&quot;width=device-width, user-scalable=no, initial-scale=1.0, maximum-scale=1.0, minimum-scale=1.0&quot;&gt;    &lt;meta http-equiv=&quot;X-UA-Compatible&quot; content=&quot;ie=edge&quot;&gt;    &lt;title&gt;vue app&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;div id=&quot;app&quot;&gt;    &lt;p&gt;&#123;&#123;desc&#125;&#125;&lt;/p&gt;&lt;/div&gt;&lt;script src=&quot;./src/vue.js&quot;&gt;&lt;/script&gt;&lt;script&gt;    const app = new Vue(&#123;        el: &#x27;#app&#x27;,        data: &#123;            desc: &#x27;HelloWorld&#x27;,        &#125;,    &#125;);&lt;/script&gt;&lt;/body&gt;&lt;/html&gt;


接下来，我们简单实现一下指令和实现，这个demo就实现一下v-text、v-html以及事件绑定@click。
首先，当我们递归节点的时候，当nodeType === 1的时候，我们得知该节点是一个元素，就可以通过node.attributes去获取该标签中的所有指令。然后通过遍历和识别attrName是否以v-或者@开头的。
if(node.nodeType === 1) &#123;    // 元素    console.log(&#x27;元素&#x27;, node.nodeName);    // 处理指令和事件    const attrs = node.attributes;    Array.from(attrs).forEach(attr =&gt; &#123;        const attrName = attr.name;        const exp = attr.value;        if (attrName.startsWith(&#x27;v-&#x27;)) &#123;            // 处理指令        &#125;        if (attrName.indexOf(&#x27;@&#x27;) === 0) &#123;            // 处理事件        &#125;    &#125;)&#125;

因为事件处理比较简单，所以我们先来处理事件。
我们只需要提取出事件的类型，然后将节点node、方法名exp和事件类型dir进行事件监听。
这里需要主要的是，addEventListener事件监听第二个参数的方法，需要绑定this.$vm，因为在方法中有可能会用到data数据。
class Compile &#123;    constructor(el, vm) &#123; ... &#125;    compile(el)&#123;        const childNodes = el.childNodes;        childNodes.forEach(node =&gt; &#123;            if(node.nodeType === 1)&#123;                const attrs = node.attributes;                Array.from(attrs).forEach(attr =&gt; &#123;                    const attrName = attr.name;                    const exp = attr.value;                    if(attrName.startsWith(&#x27;v-&#x27;))&#123;                        // 处理指令                    &#125;                    // 处理事件                    if(attrName.indexOf(&#x27;@&#x27;) === 0)&#123;                        const dir = attrName.substring(1);                        // 事件监听                        this.eventHandler(node, exp, dir);                    &#125;                &#125;)            &#125;else if(node.nodeType === 3 &amp;&amp; /\&#123;\&#123;(.*)\&#125;\&#125;/.test(node.textContent))&#123;                console.log(&#x27;文本&#x27;, node.textContent);                this.compileText(node);            &#125;            if(node.childNodes)&#123;                this.compile(node);            &#125;        &#125;)    &#125;    /**     * eventHandler: 节点事件处理     * @param node: 节点     * @param exp: 函数名     * @param dir: 事件类型     */    eventHandler(node, exp, dir) &#123;        const fn = this.$vm.$options.methods &amp;&amp; this.$vm.$options.methods[exp];        node.addEventListener(dir, fn.bind(this.$vm));    &#125;&#125;

现在来测试一下。
&lt;!doctype html&gt;&lt;html lang=&quot;en&quot;&gt;&lt;head&gt;    &lt;meta charset=&quot;UTF-8&quot;&gt;    &lt;meta name=&quot;viewport&quot;          content=&quot;width=device-width, user-scalable=no, initial-scale=1.0, maximum-scale=1.0, minimum-scale=1.0&quot;&gt;    &lt;meta http-equiv=&quot;X-UA-Compatible&quot; content=&quot;ie=edge&quot;&gt;    &lt;title&gt;vue app&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;div id=&quot;app&quot;&gt;    &lt;button @click=&quot;add&quot;&gt;测试&lt;/button&gt;&lt;/div&gt;&lt;script src=&quot;./src/vue.js&quot;&gt;&lt;/script&gt;&lt;script&gt;    const app = new Vue(&#123;        el: &#x27;#app&#x27;,        data: &#123;            desc: &#x27;HelloWorld&#x27;        &#125;,        methods:&#123;            test() &#123;                console.log(this.desc);            &#125;        &#125;    &#125;);&lt;/script&gt;&lt;/body&gt;&lt;/html&gt;


接下来来处理指令。
对不同指令的处理是不一样，因此得对每一种指令都需要新建一个更新函数。这里只实现以下v-text、v-html、v-model。
每个方法名是与指令名一致，这有利于后面直接用指令名去查找。然后每个方法都接受两个参数——node节点和exp变量名。
class Compile &#123;    constructor(el, vm) &#123; ... &#125;    compile(el)&#123; ... &#125;    // v-text    text(node, exp) &#123;        node.textContent = this.$vm[exp];    &#125;    // v-html    html(node, exp) &#123;        node.innerHTML = this.$vm[exp];    &#125;    // v-model    model(node, exp)&#123;        // 表单原生赋值        node.value = value;        // 事件监听        node.addEventListener(&#x27;input&#x27;, e =&gt; &#123;            // 赋值实现双向绑定            this.$vm[exp] = e.target.value;        &#125;)    &#125;&#125;

然后处理指令只需要直接查找一下this有没有这个指令方法，有的话调用。
// 处理指令if(attrName.startsWith(&#x27;v-&#x27;))&#123;    const dir = attrName.substring(2);    this[dir] &amp;&amp; this[dir](node, exp);&#125;

最后试验一下。
&lt;!doctype html&gt;&lt;html lang=&quot;en&quot;&gt;&lt;head&gt;    &lt;meta charset=&quot;UTF-8&quot;&gt;    &lt;meta name=&quot;viewport&quot;          content=&quot;width=device-width, user-scalable=no, initial-scale=1.0, maximum-scale=1.0, minimum-scale=1.0&quot;&gt;    &lt;meta http-equiv=&quot;X-UA-Compatible&quot; content=&quot;ie=edge&quot;&gt;    &lt;title&gt;vue app&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;div id=&quot;app&quot;&gt;    &lt;p v-text=&quot;desc&quot;&gt;&lt;/p&gt;    &lt;p v-html=&quot;desc2&quot;&gt;&lt;/p&gt;    &lt;input type=&quot;text&quot; v-model=&quot;desc&quot; /&gt;&lt;/div&gt;&lt;script src=&quot;./src/vue.js&quot;&gt;&lt;/script&gt;&lt;script&gt;    const app = new Vue(&#123;        el: &#x27;#app&#x27;,        data: &#123;            counter: 1,            desc: &#x27;HelloWorld&#x27;,            desc2: `&lt;span style=&quot;font-weight: bolder&quot;&gt;Hello World&lt;/span&gt;`        &#125;    &#125;);&lt;/script&gt;&lt;/body&gt;&lt;/html&gt;


数据更新数据的更新就会用到Watcher监听器和Dependence观察者。
当我们视图中用到了data中某个属性key，这称为依赖，比如&lt;div&gt;&#123;&#123;desc&#125;&#125;&lt;/div&gt;，desc就是一个依赖。而同一个key出现多次的时候，每一次都会创建一个Watcher来维护它们，而这个过程称为依赖收集。然而但某个key发生变化的时候，我们需要通过该依赖下的所有Watcher去更新，这时候就需要一个Dependence来管理，需要更新的时候就由它来统一通知。

在实现这个功能之前，我们需要先来重构一个地方的代码。
就是我们只需在模板中用到data属性的地方需要创建一个Watcher监听器，因此我们需要在Compile中创建。但是在其中我们插值表达式用到了一个更新方法，每个指令各用到了一个更新方法。
因此我们需要一个高级函数，将其都封装起来。也就是当用到每一种指令或插值表达式，我们都会经历调用这个高级函数，因此我们也可以在这个高级函数中创建Watcher。
class Compile &#123;    constructor(el, vm) &#123; ... &#125;    compile(el)&#123; ... &#125;    /**     * update: 高阶函数 —— 操作节点     * @param node: 节点     * @param exp: 绑定数据变量名     * @param dir: 指令名     */    update(node, exp, dir) &#123;        // 初始化        const fn = this[dir + &#x27;Updater&#x27;];        fn &amp;&amp; fn(node, this.$vm[exp]);        // TODO 创建监听器    &#125;    // 编译文本    compileText(node) &#123;        this.update(node, RegExp.$1, &#x27;text&#x27;);    &#125;    // v-text    text(node, exp) &#123;        this.update(node, exp, &#x27;text&#x27;);    &#125;    textUpdater(node, value) &#123;        node.textContent = value;    &#125;    // v-html    html(node, exp) &#123;        this.update(node, exp, &#x27;html&#x27;);    &#125;    htmlUpdater(node, value) &#123;        node.innerHTML = value;    &#125;    // v-model    model(node, exp)&#123;        this.update(node,exp, &#x27;model&#x27;);        node.addEventListener(&#x27;input&#x27;, e =&gt; &#123;            this.$vm[exp] = e.target.value;        &#125;)    &#125;    modelUpdater(node, value)&#123;        node.value = value;    &#125;    eventHandler(node, exp, dir) &#123; ... &#125;&#125;

紧接着，我们就可以来创建Watcher类。
这个类的功能其实很简单，就是保存这个更新函数，然后当数据更新的时候，我们调用一下更新函数就可以了。
/** * Watcher: *   1. 监听器 —— 负责依赖更新 * @param vm * @param key: 绑定数据变量名 * @param updateFn: 更新函数 */class Watcher &#123;    constructor(vm, key, updateFn) &#123;        this.vm = vm;        this.key = key;        this.updateFn = updateFn;    &#125;    update() &#123;        // 执行实际更新操作        this.updateFn.call(this.vm, this.vm[this.key]);    &#125;&#125;

然后在高阶函数中调用。
update(node, exp, dir) &#123;    const fn = this[dir + &#x27;Updater&#x27;];    fn &amp;&amp; fn(node, this.$vm[exp]);    // 创建Watcher监听器    new Watcher(this.$vm, exp, function (val)&#123;        fn &amp;&amp; fn(node, val);    &#125;)&#125;

而Dependence这个类，主要就三个功能：

一个是在每一次将data响应式处理的时候，都要创建一个相应的空数组deps，用于收集相应的监听器；
第二个是再每一次创建新的Watcher，都要将其放置对应的deps数组中；
第三个是每次数据更新的时候，我们就要遍历对应的deps，通知对应的所有监听器更新视图。

因此，我们就可以来实现Dependence类。
/** * Dependence: *   观察者 —— 负责通知监听器更新 */class Dependence &#123;    constructor() &#123;        this.deps = [];    &#125;    /**     * addDep: 添加新的监听器     * @param dep     */    addDep(dep) &#123;        this.deps.push(dep);    &#125;    /**     * notify: 通知更新     */    notify() &#123;        this.deps.forEach(dep =&gt; dep.update());    &#125;&#125;

然后我们在Observer类中，实现数据响应式的时候，需要创建一个Dependence实例，并且更新的时候通知更新。
class Observer &#123;    constructor(value) &#123;        this.value = value;        // 创建Dependence实例        this.dep = new Dependence();        ...    &#125;    getArrayProto() &#123;      	const self = this;              const originalProto = Array.prototype;        const arrayProto = Object.create(originalProto);        [&#x27;push&#x27;, &#x27;pop&#x27;, &#x27;shift&#x27;, &#x27;unshift&#x27;,&#x27;reverse&#x27;, &#x27;sort&#x27;, &#x27;splice&#x27;].forEach(method =&gt; &#123;            arrayProto[method] = function () &#123;                originalProto[method].apply(self, arguments);                // 覆盖操作：通知更新                self.dep.notify();            &#125;        &#125;)        return arrayProto;    &#125;    defineReactive(obj, key, val) &#123;        observe(val);         const self = this;        Object.defineProperty(obj, key, &#123;            get() &#123;                return val;            &#125;,            set(newVal) &#123;                if (newVal !== val) &#123;                     observe(newVal);                     val = newVal;                    // 通知更新                    self.dep.notify();                &#125;            &#125;        &#125;)    &#125;&#125;

最后一步，就是收集监听器。这一步的一个难点就在于我们在创建Watcher之后，需要将其放置对应key的deps中，而对应的deps，只能在对应的Observer类中才能访问到。
因此，我们可以调用一次get，来完成收集工作。
所以我们可以直接在创建完Watcher后，然后将这个this赋值给Dependence类的一个新建属性中，然后访问一下对应key，因此触发get方法，就执行收集工作。
当然对于数组也是一样得到了，我们可以调用一下push方法且不传参，就可以将Watcher实例添加到数组对应的deps中。
class Watcher &#123;    constructor(vm, key, updateFn) &#123;        this.vm = vm;        this.key = key;        this.updateFn = updateFn;        // 触发依赖收集         Dependence.target = this;   // 将this赋值给Dependence的target属性        Array.isArray(this.vm[this.key]) ? this.vm[this.key].push() : &#x27;&#x27;;  // 触发收集        Dependence.target = null;   // 收集完成后，将target设置回null    &#125;    update() &#123; ... &#125;&#125;

get() &#123;    // 依赖收集    Dependence.target &amp;&amp; self.dep.addDep(Dependence.target);    return val;&#125;

getArrayProto() &#123;    const self = this;    const originalProto = Array.prototype;    const arrayProto = Object.create(originalProto);     [&#x27;push&#x27;, &#x27;pop&#x27;, &#x27;shift&#x27;, &#x27;unshift&#x27;,&#x27;reverse&#x27;, &#x27;sort&#x27;, &#x27;splice&#x27;].forEach(method =&gt; &#123;        arrayProto[method] = function () &#123;            originalProto[method].apply(self, arguments);            // 收集监听器            Dependence.target &amp;&amp; self.dep.addDep(Dependence.target);            self.dep.notify();        &#125;    &#125;)    return arrayProto;&#125;

最后测试一下。
&lt;!doctype html&gt;&lt;html lang=&quot;en&quot;&gt;&lt;head&gt;    &lt;meta charset=&quot;UTF-8&quot;&gt;    &lt;meta name=&quot;viewport&quot;          content=&quot;width=device-width, user-scalable=no, initial-scale=1.0, maximum-scale=1.0, minimum-scale=1.0&quot;&gt;    &lt;meta http-equiv=&quot;X-UA-Compatible&quot; content=&quot;ie=edge&quot;&gt;    &lt;title&gt;vue app&lt;/title&gt;&lt;/head&gt;&lt;body&gt;&lt;div id=&quot;app&quot;&gt;    &lt;p @click=&quot;add&quot; style=&quot;cursor: pointer&quot;&gt;&#123;&#123;counter&#125;&#125;&lt;/p&gt;    &lt;p v-text=&quot;desc&quot;&gt;&lt;/p&gt;    &lt;p v-html=&quot;desc2&quot;&gt;&lt;/p&gt;    &lt;input type=&quot;text&quot; v-model=&quot;desc&quot; /&gt;    &lt;div @click=&quot;pushArr&quot;&gt;&#123;&#123;arr&#125;&#125;&lt;/div&gt;&lt;/div&gt;&lt;script src=&quot;./src/vue.js&quot;&gt;&lt;/script&gt;&lt;script&gt;    const app = new Vue(&#123;        el: &#x27;#app&#x27;,        data: &#123;            counter: 1,            desc: &#x27;HelloWorld&#x27;,            desc2: `&lt;span style=&quot;font-weight: bolder&quot;&gt;Hello World&lt;/span&gt;`,            arr: [0],        &#125;,        methods:&#123;            add() &#123;                this.counter++;            &#125;,            pushArr() &#123;                this.arr.push(this.arr.length);            &#125;        &#125;    &#125;);&lt;/script&gt;&lt;/body&gt;&lt;/html&gt;

Github

抽空梳理了一下Vue常用的组件之间的通讯方式，然后想通过使用的技术进行分类整理笔记。
Prop传值使用范围父组件向子组件传值。
使用方法父组件&lt;template&gt;  &lt;div id&#x3D;&quot;app&quot;&gt;      &lt;div class&#x3D;&quot;app&quot;&gt;          &lt;div class&#x3D;&quot;title&quot;&gt;App.vue&lt;&#x2F;div&gt;      &lt;&#x2F;div&gt;        &lt;!-- 将text1绑定给Component1 --&gt;      &lt;component1 :text&#x3D;&quot;text1&quot; &#x2F;&gt;  &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;export default &#123;    name: &#39;App&#39;,    components: &#123;        Component1,    &#125;,    data()&#123;        return&#123;            text1:&quot;Text From App.vue&quot;,        &#125;    &#125;&#125;&lt;&#x2F;script&gt;

子组件&lt;template&gt;    &lt;div class&#x3D;&quot;component1&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component1&lt;&#x2F;div&gt;        &lt;div&gt;            &lt;!-- 将父组件传递过来的text进行展示 --&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;text：&lt;&#x2F;span&gt;            &#123;&#123;text&#125;&#125;        &lt;&#x2F;div&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;export default &#123;    name: &quot;Component1&quot;,    &#x2F;&#x2F; 通过props来接收text    props:&#123;        text:&#123;            type:String        &#125;    &#125;,&#125;&lt;&#x2F;script&gt;

效果展示
注意父组件通过Prop传值给子组件是属于单向数据流，因此当父组件修改该值的时候，子组件也会随之更新数据；而子组件是不应该在内部改变 prop的。如果你可以这么做，但是Vue不推荐此做法，并会在控制台发出警告。
v-on事件绑定使用范围子组件调用父组件方法。
使用方法父组件&lt;template&gt;  &lt;div id&#x3D;&quot;app&quot;&gt;      &lt;div class&#x3D;&quot;app&quot;&gt;          &lt;div class&#x3D;&quot;title&quot;&gt;App.vue&lt;&#x2F;div&gt;          &lt;div&gt;              &lt;span class&#x3D;&quot;text-bold&quot;&gt;count：&lt;&#x2F;span&gt;              &#123;&#123;count&#125;&#125;          &lt;&#x2F;div&gt;      &lt;&#x2F;div&gt;        &lt;!-- 将事件addCount绑定给Component1 --&gt;      &lt;component1 @addCount&#x3D;&quot;addCount&quot; &#x2F;&gt;  &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;import Component1 from &quot;@&#x2F;components&#x2F;Component1&quot;;export default &#123;    name: &#39;App&#39;,    components: &#123;        Component1    &#125;,    data()&#123;        return&#123;            count:0        &#125;    &#125;,    methods:&#123;        addCount()&#123;            this.count++;        &#125;    &#125;&#125;&lt;&#x2F;script&gt;

子组件&lt;template&gt;    &lt;div class&#x3D;&quot;component1&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component1&lt;&#x2F;div&gt;        &lt;!-- Component1的button触发addParentCount --&gt;        &lt;button @click&#x3D;&quot;addParentCount&quot;&gt;            add count of App.vue        &lt;&#x2F;button&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;export default &#123;    name: &quot;Component1&quot;,    methods:&#123;        &#x2F;&#x2F; 调用组件绑定的addCount方法        addParentCount()&#123;            this.$emit(&#39;addCount&#39;)        &#125;    &#125;&#125;&lt;&#x2F;script&gt;

效果展示
注意this.$emit() 的第一个参数为事件绑定的EventName，而从第二个参数开始为函数的参数，可以传多个参数值，意味着可以通过此方法从子组件传值给父组件。
ref组件注册适用范围父组件获取子组件的值或调用子组件的方法。
使用方法父组件&lt;template&gt;  &lt;div id&#x3D;&quot;app&quot;&gt;      &lt;div class&#x3D;&quot;app&quot;&gt;          &lt;div class&#x3D;&quot;title&quot;&gt;App.vue&lt;&#x2F;div&gt;            &lt;!-- 显示获取到的子组件的text --&gt;          &lt;div&gt;              &lt;span class&#x3D;&quot;text-bold&quot;&gt;text：&lt;&#x2F;span&gt;              &#123;&#123;text2&#125;&#125;          &lt;&#x2F;div&gt;            &lt;!-- 增加子组件的count值 --&gt;          &lt;button @click&#x3D;&quot;ChildrenCount&quot;&gt;              add count of Component1.vue          &lt;&#x2F;button&gt;      &lt;&#x2F;div&gt;      &lt;!-- 进行组件注册 --&gt;      &lt;component1 ref&#x3D;&quot;component1&quot; &#x2F;&gt;  &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;import Component1 from &quot;@&#x2F;components&#x2F;Component1&quot;;export default &#123;    name: &#39;App&#39;,    components: &#123;        Component1,    &#125;,    data()&#123;        return&#123;            text2:&#39;&#39;        &#125;    &#125;,    mounted() &#123;        &#x2F;&#x2F; 获取子组件的text1值        this.text2 &#x3D; this.$refs.component1.text1 || &#39;&#39;;    &#125;,    methods:&#123;        &#x2F;&#x2F; 调用子组件的方法        ChildrenCount()&#123;            this.$refs.component1.addCount();        &#125;    &#125;&#125;&lt;&#x2F;script&gt;

子组件&lt;template&gt;    &lt;div class&#x3D;&quot;component1&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component1&lt;&#x2F;div&gt;        &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;count：&lt;&#x2F;span&gt;            &#123;&#123;count&#125;&#125;        &lt;&#x2F;div&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;export default &#123;    name: &quot;Component1&quot;,    data()&#123;        return&#123;            &#x2F;&#x2F; 父组件获取到此值            text1: &#39;Text From Component1.vue&#39;,            count: 0        &#125;    &#125;,    methods:&#123;        &#x2F;&#x2F; 父组件调用此方法        addCount()&#123;            this.count++;        &#125;    &#125;&#125;&lt;&#x2F;script&gt;

效果
注意this.$refs 是组件渲染后才会进行填充，因此无法在计算属性 computed 使用，打印出来会显示 undefined 。
EventBus事件总线使用范围任意组件间的事件调用。
使用方法初始化EventBus共有两种方式可以初始化EventBus，第一种方式是新建一个 eventBus.js ，内容如下：
import Vue from &#x27;vue&#x27;export const EventBus = new Vue()

然后使用时均在两个组件内引入该文件。
import &#123; EventBus &#125; from &quot;../eventBus.js&quot;;

而第二种方式是全局注册EventBus。
在项目的 main.js 文件下，插入注册代码：
Vue.prototype.$EventBus = new Vue()

然后使用时即可通过 this.$EventBus 调用。
后面的案例均用第二种方法实现。
第一个组件&lt;template&gt;    &lt;div class&#x3D;&quot;component2&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component2&lt;&#x2F;div&gt;            &lt;!-- 获取input值更新另一个组件的count值 --&gt;        &lt;div&gt;            &lt;input type&#x3D;&quot;number&quot; placeholder&#x3D;&quot;Number...&quot; v-model&#x3D;&quot;value&quot;&gt;        &lt;&#x2F;div&gt;        &lt;!-- 点击button触发事件 --&gt;        &lt;button @click&#x3D;&quot;changeComponent1Count&quot;&gt;            change count of Component1        &lt;&#x2F;button&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;export default &#123;    name: &quot;Component2&quot;,    data() &#123;        return &#123;            value:&#39;&#39;        &#125;    &#125;,    methods:&#123;        &#x2F;&#x2F; 在EventBus总线注册changeCount事件，并将value值传过去        changeComponent1Count()&#123;            this.$EventBus.$emit(&quot;changeCount&quot;,this.value)        &#125;    &#125;&#125;&lt;&#x2F;script&gt;

第二个组件&lt;template&gt;    &lt;div class&#x3D;&quot;component1&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component1&lt;&#x2F;div&gt;        &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;count：&lt;&#x2F;span&gt;            &#123;&#123;count&#125;&#125;        &lt;&#x2F;div&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;export default &#123;    name: &quot;Component1&quot;,    data()&#123;        return&#123;            count: 0        &#125;    &#125;,    &#x2F;&#x2F; 在mounted中监听EventBus接收changeCount事件，并触发回调函数将value值赋给count    mounted()&#123;        this.$EventBus.$on(&#39;changeCount&#39;,(value)&#x3D;&gt; this.count &#x3D; value);    &#125;&#125;&lt;&#x2F;script&gt;

效果
注意虽然在Vue中可以使用 EventBus 来作为沟通桥梁的概念，就像是所有组件共用相同的事件中心，可以向该中心注册发送事件或接收事件，使得所有组件都可以上下平行地通知其他组件，但是若使用不慎，就会造成难以维护的“灾难”。
Vue是单页应用，如果你在某一个页面刷新了之后，与之相关的 EventBus 会被移除，这样就导致业务走不下去。还要就是如果业务有反复操作的页面， EventBus 在监听的时候就会触发很多次，也是一个非常大的隐患。这时候我们就需要好好处理 EventBus 在项目中的关系。通常会用到，在vue页面销毁时，同时移除 EventBus 事件监听。
移除EventBus 事件监听的方法如下：
// 移除指定事件this.$EventBus.$off(&#x27;changeCount&#x27;)// 移除所有事件this.$EventBus.$off()

$parent与$children使用范围通过插槽嵌套的父子组件进行事件调用和传值。
使用方法App.vue&lt;template&gt;  &lt;div id&#x3D;&quot;app&quot;&gt;      &lt;component3&gt;          &lt;component4&gt;&lt;&#x2F;component4&gt;      &lt;&#x2F;component3&gt;  &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;import Component3 from &quot;@&#x2F;components&#x2F;Component3&quot;;import Component4 from &quot;@&#x2F;components&#x2F;Component4&quot;;export default &#123;    name: &#39;App&#39;,    components: &#123;        Component3,        Component4,    &#125;&#125;&lt;&#x2F;script&gt;

父组件&lt;template&gt;    &lt;div class&#x3D;&quot;component3&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component3&lt;&#x2F;div&gt;        &lt;!-- 获取到子组件的text1值 --&gt;        &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;text：&lt;&#x2F;span&gt;            &#123;&#123;text2&#125;&#125;        &lt;&#x2F;div&gt;              &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;count：&lt;&#x2F;span&gt;            &#123;&#123;count&#125;&#125;        &lt;&#x2F;div&gt;        &lt;!-- 增加子组件的count值 --&gt;        &lt;button @click&#x3D;&quot;addChildrenCount&quot;&gt;            add count of Component4.vue        &lt;&#x2F;button&gt;              &lt;!-- 插槽 --&gt;        &lt;slot&gt;&lt;&#x2F;slot&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;export default &#123;    name: &quot;Component3&quot;,    data() &#123;        return &#123;            text1: &#39;Text From Component3.vue&#39;,            text2:&#39;&#39;,            count: 0        &#125;    &#125;,    mounted() &#123;        &#x2F;&#x2F; 获取子组件的text1值        this.text2 &#x3D; this.$children[0].text1;        &#x2F;&#x2F; 监听子组件调用changeCount，并将参数value赋值给父组件的count        this.$on(&quot;changeCount&quot;,value &#x3D;&gt; this.count &#x3D; value);    &#125;,    methods:&#123;        addChildrenCount()&#123;            &#x2F;&#x2F; 调用第一个子组件绑定的addCount方法            this.$children[0].$emit(&#39;addCount&#39;);        &#125;    &#125;&#125;&lt;&#x2F;script&gt;

子组件&lt;template&gt;    &lt;div class&#x3D;&quot;component4&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component4&lt;&#x2F;div&gt;        &lt;!-- 获取到父组件的text1值 --&gt;        &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;text：&lt;&#x2F;span&gt;            &#123;&#123;text2&#125;&#125;        &lt;&#x2F;div&gt;              &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;count：&lt;&#x2F;span&gt;            &#123;&#123;count&#125;&#125;        &lt;&#x2F;div&gt;              &lt;div&gt;            &lt;input type&#x3D;&quot;number&quot; placeholder&#x3D;&quot;Number...&quot; v-model&#x3D;&quot;value&quot;&gt;        &lt;&#x2F;div&gt;        &lt;!-- 修改父组件的count值 --&gt;        &lt;button @click&#x3D;&quot;changeParentCount&quot;&gt;            change count of Component3.vue        &lt;&#x2F;button&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;export default &#123;    name: &quot;Component4&quot;,    data() &#123;        return &#123;            text1: &#39;Text From Component4.vue&#39;,            text2:&#39;&#39;,            count: 0,            value:&#39;&#39;        &#125;    &#125;,    mounted() &#123;        &#x2F;&#x2F; 获取父组件的text1值        this.text2 &#x3D; this.$parent.text1;        &#x2F;&#x2F; 监听父组件调用addCount，并将count++        this.$on(&#39;addCount&#39;,() &#x3D;&gt; this.count++);    &#125;,    methods:&#123;        changeParentCount()&#123;            &#x2F;&#x2F; 调用父组件绑定的changeCount方法，并传入value参数            this.$parent.$emit(&#39;changeCount&#39;,this.value)        &#125;,    &#125;&#125;&lt;&#x2F;script&gt;

效果
注意同 $refs ， $parent 和 $children 是组件渲染后才会进行填充，因此无法在计算属性 computed 使用。
$children 返回的是一个数组，一个父组件可能有多个子组件，但一个子组件只能有一个父组件。
provide与inject使用范围父组件向任一后代组件传值和方法，适用于正常嵌套和插槽嵌套。
使用方法App.vue&lt;template&gt;  &lt;div id&#x3D;&quot;app&quot;&gt;      &lt;component3&gt;          &lt;component4&gt;              &lt;component5&gt;&lt;&#x2F;component5&gt;          &lt;&#x2F;component4&gt;      &lt;&#x2F;component3&gt;  &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;import Component3 from &quot;@&#x2F;components&#x2F;Component3&quot;;import Component4 from &quot;@&#x2F;components&#x2F;Component4&quot;;import Component5 from &quot;@&#x2F;components&#x2F;Component5&quot;;export default &#123;    name: &#39;App&#39;,    components: &#123;        Component3,        Component4,        Component5,    &#125;,&#125;&lt;&#x2F;script&gt;

父组件&lt;template&gt;    &lt;div class&#x3D;&quot;component3&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component3&lt;&#x2F;div&gt;        &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;count：&lt;&#x2F;span&gt;            &#123;&#123;count&#125;&#125;        &lt;&#x2F;div&gt;        &lt;!-- 插槽 --&gt;        &lt;slot&gt;&lt;&#x2F;slot&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;export default &#123;    name: &quot;Component3&quot;,    &#x2F;&#x2F; 向后代组件提供text和执行上下文this    provide()&#123;        return&#123;            text:this.text1,            component3:this        &#125;    &#125;,    methods:&#123;        addCount()&#123;            this.count++;        &#125;    &#125;&#125;&lt;&#x2F;script&gt;

子组件&lt;template&gt;    &lt;div class&#x3D;&quot;component4&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component4&lt;&#x2F;div&gt;、        &lt;!-- 显示父组件的text值 --&gt;        &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;text：&lt;&#x2F;span&gt;            &#123;&#123;text&#125;&#125;        &lt;&#x2F;div&gt;        &lt;slot&gt;&lt;&#x2F;slot&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;export default &#123;    name: &quot;Component4&quot;,    &#x2F;&#x2F; 接收父组件的text值    inject:[&#39;text&#39;]&#125;&lt;&#x2F;script&gt;

孙组件&lt;template&gt;    &lt;div class&#x3D;&quot;component5&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component5&lt;&#x2F;div&gt;        &lt;!-- 显示祖组件的text值 --&gt;        &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;text：&lt;&#x2F;span&gt;            &#123;&#123;text&#125;&#125;        &lt;&#x2F;div&gt;        &lt;!-- 增加祖组件的count值 --&gt;        &lt;button @click&#x3D;&quot;addGrandParentCount&quot;&gt;            add count of Component3.vue        &lt;&#x2F;button&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;export default &#123;    name: &quot;Component5&quot;,    &#x2F;&#x2F; 接收祖组件的text值和执行上下文    inject:[&#39;text&#39;,&#39;component3&#39;],    methods:&#123;        &#x2F;&#x2F; 通过祖组件执行上下文调用其方法        addGrandParentCount()&#123;            this.component3.addCount();        &#125;    &#125;&#125;&lt;&#x2F;script&gt;

效果
$attrs与$listeners使用范围孙组件获取祖组件的值或调用祖组件事件。
使用方法祖组件&lt;template&gt;    &lt;div class&#x3D;&quot;component6&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component6&lt;&#x2F;div&gt;        &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;count：&lt;&#x2F;span&gt;            &#123;&#123;count&#125;&#125;        &lt;&#x2F;div&gt;                        &lt;!-- 祖组件向自己组件传递了text1与text2和一个addCount事件 --&gt;        &lt;component7 :text1&#x3D;&quot;text&quot; :text2&#x3D;&quot;text&quot; @addCount&#x3D;&quot;addCount&quot; &#x2F;&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;import Component7 from &quot;@&#x2F;components&#x2F;Component7&quot;;export default &#123;    name: &quot;Component6&quot;,    components:&#123;        Component7    &#125;,    data() &#123;        return &#123;            text: &#39;Text From Component6.vue&#39;,            count: 0        &#125;    &#125;,    methods:&#123;        addCount()&#123;            this.count ++        &#125;    &#125;&#125;&lt;&#x2F;script&gt;

父组件&lt;template&gt;    &lt;div class&#x3D;&quot;component7&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component7&lt;&#x2F;div&gt;        &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;text：&lt;&#x2F;span&gt;            &#123;&#123;text1&#125;&#125;        &lt;&#x2F;div&gt;        &lt;!-- 将不被父组件prop识别的attribute绑定到孙组件，也将祖组件的事件绑定到孙组件 --&gt;        &lt;component8 v-bind&#x3D;&quot;$attrs&quot; v-on&#x3D;&quot;$listeners&quot; &#x2F;&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;import Component8 from &quot;@&#x2F;components&#x2F;Component8&quot;;export default &#123;    name: &quot;Component7&quot;,    &#x2F;&#x2F; 父组件prop识别了text1，因此text1不会传递到孙组件    props:&#123;        text1:&#123;            type:String        &#125;    &#125;,    components:&#123;        Component8    &#125;&#125;&lt;&#x2F;script&gt;

孙组件&lt;template&gt;    &lt;div class&#x3D;&quot;component8&quot;&gt;        &lt;div class&#x3D;&quot;title&quot;&gt;Component8&lt;&#x2F;div&gt;        &lt;div&gt;            &lt;span class&#x3D;&quot;text-bold&quot;&gt;text：&lt;&#x2F;span&gt;            &#123;&#123;text2&#125;&#125;        &lt;&#x2F;div&gt;        &lt;button @click&#x3D;&quot;addGrandparentCount&quot;&gt;            add count of Component6.vue        &lt;&#x2F;button&gt;    &lt;&#x2F;div&gt;&lt;&#x2F;template&gt;&lt;script&gt;export default &#123;    name: &quot;Component8&quot;,    &#x2F;&#x2F; 孙组件获取到祖组件的text2    props:&#123;        text2:&#123;            type:String        &#125;,    &#125;,    methods:&#123;        &#x2F;&#x2F; 孙组件调用了祖组件的addCount事件        addGrandparentCount()&#123;            this.$emit(&#39;addCount&#39;);        &#125;    &#125;&#125;&lt;&#x2F;script&gt;

效果
注意$attrs 包含了父作用域中不作为 prop 被识别 (且获取) 的 attribute 绑定 (class 和 style 除外)。因此当 text1 已被子组件prop获取后，在孙组件是获取不到 text1 的。
